(function(){const a=document.querySelector('.hw-card-list'),b=Array.from(document.querySelectorAll('.hw-card')),c=document.querySelector('.progress'),d=[document.querySelector('.hw-card_img._11'),document.querySelector('.hw-card_img._2'),document.querySelector('.hw-card_img._3')],e=[document.querySelector('.hw-img-clmn_desc .hw-card_text._1'),document.querySelector('.hw-img-clmn_desc .hw-card_text._2'),document.querySelector('.hw-img-clmn_desc .hw-card_text._3')];if(!a||!b.length)return;d.forEach(el=>{if(el)el.style.transition='opacity 0.4s ease';});let f=-1;function g(i){if(f===i)return;f=i;d.forEach((img,j)=>{if(img)img.style.opacity=j===i?'1':'0';});e.forEach((txt,j)=>{if(txt)txt.style.display=j===i?'flex':'none';});}function h(){const mid=window.innerHeight*.5;let best=0,bestDist=Infinity;b.forEach((card,i)=>{const r=card.getBoundingClientRect(),dist=Math.abs((r.top+r.height/2)-mid);if(dist<bestDist){bestDist=dist;best=i;}});return best;}let rafId;function tick(){const r=a.getBoundingClientRect(),wh=window.innerHeight;if(c){const pct=Math.max(0,Math.min(1,(wh-r.top)/(r.height+wh)));c.style.height=(pct*100)+'%';}g(h());}window.addEventListener('scroll',()=>{cancelAnimationFrame(rafId);rafId=requestAnimationFrame(tick);},{passive:true});tick();})();
